#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int *arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        qsort(arr, N, sizeof(int), compare);
        long long sum = 0;
        long long total = 0;
        for (int i = 0; i < N; i++) {
            sum += arr[i];
            total += sum;
        }
        printf("%lld\n", total);
        free(arr);
    }
    return 0;
}

