const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextInt() {
    return parseInt(lines[idx++]);
}

function nextIntArray() {
    return lines[idx++].split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let N = nextInt();
    let arr = nextIntArray();
    arr.sort((a, b) => a - b);
    let sum = 0;
    let total = 0;
    for (let i = 0; i < N; i++) {
        sum += arr[i];
        total += sum;
    }
